```1:169:/Users/duhl/git/ui/apps/org-next/tests/campaigns.spec.ts
import { expect, test } from "./test-fixture";

const usersApiPattern = /http:\/\/localhost:3210\/users\/me/;
const tenantsApiPattern = /http:\/\/localhost:3210\/tenants/;
const campaignsIndexPattern =
  /http:\/\/localhost:3210\/campaigns\?[^#]*tenant_id=42/;
const createCampaignPattern =
  /http:\/\/localhost:3210\/campaigns\?[^#]*tenant_id=42$/;
const campaignShowPattern =
  /http:\/\/localhost:3210\/campaigns\/101\?[^#]*tenant_id=42/;

const mockUser = {
  id: 1,
  email: "test@example.com",
  cognito_sub: null,
  created_at: "2024-01-01T00:00:00Z",
  updated_at: "2024-01-01T00:00:00Z",
};

const mockOrgTenant = {
  id: 42,
  tenant_type: "org" as const,
  name: "Hope Foundation",
  org_id: "org-42",
  vendor_id: null,
  created_at: "2024-01-01T00:00:00Z",
  updated_at: "2024-01-01T00:00:00Z",
};

const mockCampaign = {
  id: 101,
  name: "Spring Drive",
  created_at: "2024-02-01T00:00:00Z",
  updated_at: "2024-02-02T00:00:00Z",
};

test("homepage lists campaigns from API and opens campaign detail", async ({
  page,
  mockServerRequest,
}) => {
  await mockServerRequest.GET(usersApiPattern, { body: mockUser });
  await mockServerRequest.GET(tenantsApiPattern, { body: [mockOrgTenant] });
  await mockServerRequest.GET(campaignsIndexPattern, { body: [mockCampaign] });
  await mockServerRequest.GET(campaignShowPattern, { body: mockCampaign });

  await page.goto("/", { waitUntil: "networkidle" });

  await expect(page.getByText("Spring Drive")).toBeVisible();

  await page.getByRole("link", { name: /Spring Drive/ }).click();

  await expect(page).toHaveURL(/\/campaigns\/101$/);
  await expect(
    page.getByRole("heading", { name: "Spring Drive", exact: true }),
  ).toBeVisible();
  await expect(page.getByText("Campaign details")).toBeVisible();
  await expect(page.getByText("101")).toBeVisible();
});

test("creates a campaign from the homepage modal and navigates to its detail page without client errors", async ({
  page,
  mockServerRequest,
}) => {
  const pageErrors: string[] = [];
  const consoleErrors: string[] = [];

  page.on("pageerror", (error) => {
    pageErrors.push(error.message);
  });
  page.on("console", (message) => {
    if (message.type() === "error") {
      consoleErrors.push(message.text());
    }
  });

  await mockServerRequest.GET(usersApiPattern, { body: mockUser });
  await mockServerRequest.GET(tenantsApiPattern, { body: [mockOrgTenant] });
  await mockServerRequest.GET(campaignsIndexPattern, { body: [] });

  await page.goto("/", { waitUntil: "networkidle" });

  const newCampaignButton = page.getByRole("button", {
    name: /New campaign/i,
  });
  await newCampaignButton.click();

  const dialog = page.getByRole("dialog");
  await expect(dialog).toBeVisible();
  await expect(
    dialog.getByRole("heading", { name: /Create campaign/i }),
  ).toBeVisible();

  await dialog.locator("#create-campaign-modal-name").fill("Spring Drive");

  await mockServerRequest.reset();
  await mockServerRequest.GET(usersApiPattern, { body: mockUser });
  await mockServerRequest.GET(tenantsApiPattern, { body: [mockOrgTenant] });
  await mockServerRequest.GET(campaignsIndexPattern, { body: [] });
  await mockServerRequest.POST(createCampaignPattern, { body: mockCampaign });
  await mockServerRequest.GET(campaignShowPattern, { body: mockCampaign });

  await dialog.getByRole("button", { name: "Create campaign" }).click();

  // wait for the campaign to be created before redirecting
  await page.waitForURL(/\/campaigns\/101$/);

  await expect(
    page.getByRole("heading", { name: "Spring Drive", exact: true }),
  ).toBeVisible();
  expect(pageErrors).toEqual([]);
  expect(consoleErrors.some((message) => message.includes("removeChild"))).toBe(
    false,
  );
});

test("vendor tenant does not see org create-campaign entry points on the homepage", async ({
  page,
  mockServerRequest,
}) => {
  const vendorTenant = {
    id: 43,
    tenant_type: "vendor" as const,
    name: "Acme Vendor",
    org_id: null,
    vendor_id: "ven-43",
    created_at: "2024-01-01T00:00:00Z",
    updated_at: "2024-01-01T00:00:00Z",
  };

  await mockServerRequest.GET(usersApiPattern, { body: mockUser });
  await mockServerRequest.GET(tenantsApiPattern, { body: [vendorTenant] });
  await mockServerRequest.GET(
    /http:\/\/localhost:3210\/campaigns\?[^#]*tenant_id=43[^#]*vendor_id=43/,
    { body: [] },
  );

  await page.goto("/", { waitUntil: "networkidle" });

  await expect(page.getByRole("button", { name: /New campaign/i })).toHaveCount(
    0,
  );
});

test("legacy /campaigns/new URL redirects to the homepage", async ({
  page,
  mockServerRequest,
}) => {
  const vendorTenant = {
    id: 43,
    tenant_type: "vendor" as const,
    name: "Acme Vendor",
    org_id: null,
    vendor_id: "ven-43",
    created_at: "2024-01-01T00:00:00Z",
    updated_at: "2024-01-01T00:00:00Z",
  };

  await mockServerRequest.GET(usersApiPattern, { body: mockUser });
  await mockServerRequest.GET(tenantsApiPattern, { body: [vendorTenant] });
  await mockServerRequest.GET(
    /http:\/\/localhost:3210\/campaigns\?[^#]*tenant_id=43[^#]*vendor_id=43/,
    { body: [] },
  );

  await page.goto("/campaigns/new", { waitUntil: "networkidle" });

  await expect(page).toHaveURL(/^http:\/\/localhost:3210\/?$/);
});
